import React from 'react';

export default function NavLogo() {
  return (
    <div className="nav-logo">
      <div className="nav-logo-box">
        <img 
          src="/logowht.png"  
          alt="Logo"
          style={{ width: 30, height: 30, objectFit: 'contain' }}
        />
      </div>
      <span className="nav-logo-text">UG-MURO</span>
    </div>
  );
}
